/**
 * Normalizes category values for case-insensitive and accent-insensitive lookups.
 * @param {string} value
 * @returns {string}
 */
export function normalizeCategoryLookup(value) {
  return String(value ?? '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim();
}

/**
 * Returns the canonical category key for a localized or raw category label.
 * @param {string | null | undefined} value
 * @returns {string | null}
 */
export function getCanonicalCategoryKey(value) {
  const normalizedValue = normalizeCategoryLookup(value);
  return CATEGORY_CANONICAL_BY_ALIAS[normalizedValue] ?? null;
}

/**
 * Returns the stable URL value for a selected category.
 * @param {string | null | undefined} category
 * @param {string} [allCategory='Todos']
 * @returns {string}
 */
export function getCategoryParamValue(category, allCategory = 'Todos') {
  const canonicalCategoryKey = getCanonicalCategoryKey(category);
  if (!category || category === allCategory || canonicalCategoryKey === 'all') {
    return '';
  }

  return canonicalCategoryKey ?? normalizeCategoryLookup(category);
}

/**
 * Builds a stable Home filter href for a category selection.
 * @param {string | null | undefined} category
 * @param {string} [basePath='/']
 * @param {string} [allCategory='Todos']
 * @returns {string}
 */
export function buildCategoryFilterHref(category, basePath = '/', allCategory = 'Todos') {
  const categoryParamValue = getCategoryParamValue(category, allCategory);
  if (!categoryParamValue) {
    return basePath;
  }

  return `${basePath}?categoria=${encodeURIComponent(categoryParamValue)}`;
}

/**
 * Checks whether two category labels refer to the same canonical category.
 * @param {string | null | undefined} leftCategory
 * @param {string | null | undefined} rightCategory
 * @returns {boolean}
 */
export function areSameCategory(leftCategory, rightCategory) {
  const leftCanonicalCategory = getCanonicalCategoryKey(leftCategory);
  const rightCanonicalCategory = getCanonicalCategoryKey(rightCategory);

  if (leftCanonicalCategory && rightCanonicalCategory) {
    return leftCanonicalCategory === rightCanonicalCategory;
  }

  return normalizeCategoryLookup(leftCategory) === normalizeCategoryLookup(rightCategory);
}

/**
 * Resolves a category query param to the closest in-app category label.
 * This keeps shared URLs resilient to accent, case, and common translated aliases.
 * @param {string | null} categoryParam
 * @param {Array<string>} categories
 * @param {string} [allCategory='Todos']
 * @returns {string}
 */
export function resolveCategorySelection(categoryParam, categories, allCategory = 'Todos') {
  const availableCategories = Array.isArray(categories) ? categories : [];
  const fallbackCategory = availableCategories.includes(allCategory)
    ? allCategory
    : (availableCategories[0] ?? allCategory);

  if (!categoryParam) {
    return fallbackCategory;
  }

  const canonicalParam = getCanonicalCategoryKey(categoryParam);
  if (canonicalParam === 'all') {
    return fallbackCategory;
  }

  const normalizedCategoryMap = new Map(
    availableCategories.map((category) => [normalizeCategoryLookup(category), category])
  );

  if (canonicalParam) {
    const canonicalCategoryMatch = availableCategories.find(
      (category) => getCanonicalCategoryKey(category) === canonicalParam
    );
    if (canonicalCategoryMatch) {
      return canonicalCategoryMatch;
    }
  }

  const normalizedParam = normalizeCategoryLookup(categoryParam);

  return normalizedCategoryMap.get(normalizedParam) ?? fallbackCategory;
}